external_knowledge:
- 'biggest spenders' refers to customers who have spent the most money; 
- 'total amount they spent' refers to the sum of the products of quantity and unit price of their orders;
- 'loyalty points' refers to the loyalty points earned by customers based on their total spent amount.

sql:
SELECT o.customer_id
FROM orders o
WHERE o.total = (
  SELECT MAX(o2.total)
  FROM orders o2
);

SELECT order_id
FROM invoices
WHERE total_amount = (
  SELECT MAX(total_amount)
  FROM invoices
);
